  /**
   * Validate that a plugin implements the required interface
   */
  _validatePlugin(plugin, name) {
    if (!plugin || typeof plugin !== 'object') {
      console.error(`[PluginManager] Plugin '${name}' does not export a valid object.`);
      return false;
    }

    const hasHook =
      typeof plugin.onRequest === 'function' ||
      typeof plugin.onResponse === 'function' ||
      typeof plugin.onError === 'function' ||
      typeof plugin.onStartup === 'function' ||
      typeof plugin.onShutdown === 'function';

    if (!hasHook) {
      console.error(
        `[PluginManager] Plugin '${name}' does not implement any recognized hooks ` +
        `(onRequest, onResponse, onError, onStartup, onShutdown).`
      );
      return false;
    }

    return true;
  }

  /**
   * Register plugin hooks
   */
  _registerHooks(name, plugin) {
    for (const hookName of Object.keys(this.hooks)) {
      if (typeof plugin[hookName] === 'function') {
        this.hooks[hookName].push({
          pluginName: name,
          handler: plugin[hookName].bind(plugin),
          priority: plugin.priority || 100,
        });

        // Sort by priority (lower number = higher priority)
        this.hooks[hookName].sort((a, b) => a.priority - b.priority);

        console.log(`[PluginManager] Registered hook '${hookName}' for plugin '${name}' (priority: ${plugin.priority || 100})`);
      }
    }
  }

  /**
   * Execute all handlers for a specific hook
   */
  async executeHook(hookName, context) {
    const handlers = this.hooks[hookName] || [];

    for (const { pluginName, handler } of handlers) {
      try {
        const result = await Promise.resolve(handler(context));

        // If a handler returns false, stop the chain
        if (result === false) {
          console.log(`[PluginManager] Hook chain '${hookName}' stopped by plugin '${pluginName}'.`);
          return false;
        }

        // If a handler returns a modified context, use it
        if (result && typeof result === 'object') {
          Object.assign(context, result);
        }
      } catch (err) {
        console.error(
          `[PluginManager] Error in plugin '${pluginName}' hook '${hookName}': ${err.message}`
        );

        // Execute error hooks if this isn't already an error hook
        if (hookName !== 'onError') {
          await this.executeHook('onError', {
            ...context,
            error: err,
            sourcePlugin: pluginName,
            sourceHook: hookName,
          });
        }
      }
    }

    return context;
  }

  /**
   * Unload a plugin
   */
  unloadPlugin(name) {
    if (!this.plugins.has(name)) {
      console.warn(`[PluginManager] Plugin '${name}' not found.`);
      return false;
    }

    const pluginData = this.plugins.get(name);

    // Call shutdown hook if available
    if (typeof pluginData.instance.onShutdown === 'function') {
      try {
        pluginData.instance.onShutdown();
      } catch (err) {
        console.error(`[PluginManager] Error during shutdown of plugin '${name}': ${err.message}`);
      }
    }

    // Remove from hooks
    for (const hookName of Object.keys(this.hooks)) {
      this.hooks[hookName] = this.hooks[hookName].filter(h => h.pluginName !== name);
    }

    this.plugins.delete(name);
    console.log(`[PluginManager] Plugin '${name}' unloaded.`);
    return true;
  }

  /**
   * Reload a plugin
   */
  reloadPlugin(name) {
    const pluginData = this.plugins.get(name);
    if (!pluginData) {
      console.error(`[PluginManager] Plugin '${name}' not found for reload.`);
      return false;
    }

    this.unloadPlugin(name);
    this.loadPlugin(pluginData.definition);
    return true;
  }

  /**
   * List all loaded plugins
   */
  listPlugins() {
    const list = [];
    for (const [name, data] of this.plugins) {
      list.push({
        name,
        loadedAt: data.loadedAt,
        hooks: Object.keys(this.hooks).filter(h =>
          this.hooks[h].some(handler => handler.pluginName === name)
        ),
        config: data.definition.config || {},
      });
    }
    return list;
  }
