class GatewayContext {
  constructor(req, res) {
    this.req = req;
    this.res = res;
    this.requestId = this._generateId();
    this.startTime = Date.now();
    this.state = {}; // Shared state between plugins
    this.headers = { ...req.headers };
    this.method = req.method;
    this.url = req.url;
    this.parsedUrl = url.parse(req.url, true);
    this.path = this.parsedUrl.pathname;
    this.query = this.parsedUrl.query;
    this.body = null;
    this.responseBody = null;
    this.responseHeaders = {};
    this.responseStatusCode = 200;
    this.upstreamResponse = null;
    this.aborted = false;
    this.metadata = {};
  }

  _generateId() {
    return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  }

  setResponseHeader(name, value) {
    this.responseHeaders[name.toLowerCase()] = value;
  }

  setStatusCode(code) {
    this.responseStatusCode = code;
  }

  setResponseBody(body) {
    this.responseBody = body;
  }

  abort(statusCode = 403, message = 'Request blocked') {
    this.aborted = true;
    this.responseStatusCode = statusCode;
    this.responseBody = JSON.stringify({ error: message, requestId: this.requestId });
  }

  getElapsedTime() {
    return Date.now() - this.startTime;
  }
}

// ============================================================
// API Gateway
