// ============================================================
// Mock upstream server for testing
// ============================================================
function createMockUpstream(port, name) {
  const server = http.createServer((req, res) => {
    const body = JSON.stringify({
      service: name,
      path: req.url,
      method: req.method,
      headers: req.headers,
      timestamp: new Date().toISOString(),
      message: `Response from ${name} service`,
    });

    res.writeHead(200, {
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(body),
    });
    res.end(body);
  });

  server.listen(port, () => {
    console.log(`[Mock] ${name} service listening on port ${port}`);
  });

  return server;
}

// ============================================================
// Main entry point
// ============================================================
async function main() {
  const args = process.argv.slice(2);

  if (args.includes('--setup')) {
    createExamplePlugins();
    createExampleConfig();
    console.log('\n[Setup] Setup complete! Run the gateway with: node gateway.js');
    console.log('[Setup] Or run with mock upstreams: node gateway.js --mock');
    return;
  }

  // Create example files if they don't exist
  if (!fs.existsSync(path.join(process.cwd(), 'gateway.config.json'))) {
    console.log('[Gateway] No configuration found, creating example setup...');
    createExamplePlugins();
    createExampleConfig();
  }

  // Start mock upstream servers if requested
  if (args.includes('--mock')) {
    createMockUpstream(8001, 'users');
    createMockUpstream(8002, 'products');
    createMockUpstream(8003, 'orders');
  }

  // Start the gateway
  const gateway = new APIGateway();
  await gateway.start();

  console.log('\n[Gateway] ===================================');
  console.log('[Gateway] API Gateway is running!');
  console.log(`[Gateway] Proxy:  http://localhost:${gateway.options.port}`);
  console.log(`[Gateway] Admin:  http://localhost:${gateway.options.adminPort}`);
  console.log('[Gateway] ===================================');
  console.log('\n[Gateway] Admin API endpoints:');
  console.log('  GET    /health          - Gateway health check');
  console.log('  GET    /plugins         - List loaded plugins');
  console.log('  POST   /plugins/load    - Load a new plugin');
  console.log('  POST   /plugins/unload  - Unload a plugin');
  console.log('  POST   /plugins/reload  - Reload a plugin');
  console.log('  GET    /routes          - List routes');
  console.log('  POST   /routes          - Add a route');
  console.log('');
}

main().catch(console.error);

module.exports = { APIGateway, PluginManager, GatewayContext };